1	// COR24 APL Interpreter -- Tokenizer
2	// Lexes input line into token array for the parser.
3	
4	#pragma once
5	
6	// Token types
7	#define TOK_EOL     0   // end of line
8	#define TOK_NUM     1   // integer literal (value in tok_val)
9	#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
10	#define TOK_PLUS    3   // +
11	#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
12	#define TOK_STAR    5   // *
13	#define TOK_SLASH   6   // /
14	#define TOK_LPAREN  7   // (
15	#define TOK_RPAREN  8   // )
16	#define TOK_ASSIGN  9   // <-
17	#define TOK_RES    10   // reserved word (ID in tok_val)
18	#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
19	#define TOK_QLED   12   // qled — LED D2 hardware I/O
20	#define TOK_QSW    13   // qsw — switch S2 hardware I/O (read-only)
21	#define TOK_QSVO   14   // qsvo — shared variable offer (□SVO)
22	#define TOK_LBRAK  15   // [ (bracket index open)
23	#define TOK_RBRAK  16   // ] (bracket index close)
24	#define TOK_GOTO   17   // goto — branch (→)
25	#define TOK_STRING 18   // string literal 'ABC' (pos of first char in tok_val)
26	#define TOK_EQ     19   // =
27	#define TOK_NE     20   // !=
28	#define TOK_LT     21   // <
29	#define TOK_GT     22   // >
30	#define TOK_LE     23   // <=
31	#define TOK_GE     24   // >=
32	
33	// Reserved word IDs
34	#define RES_RHO     0
35	#define RES_IOTA    1
36	#define RES_TAKE    2
37	#define RES_DROP    3
38	#define RES_REV     4
39	#define RES_CAT     5
40	#define RES_AND     6
41	#define RES_OR      7
42	#define RES_NOT     8
43	
44	#define TOK_MAX    64   // max tokens per line
45	
46	// Token storage (parallel arrays)
47	int tok_type[TOK_MAX];  // token type
48	int tok_val[TOK_MAX];   // numeric value or reserved word ID
49	int tok_pos[TOK_MAX];   // start position in source line
50	int tok_count;           // number of tokens produced
51	
52	// ---- String helpers ----
53	
54	// Compare a substring of src starting at pos against a NUL-terminated word.
55	// Returns 1 if match, 0 otherwise.
56	int str_match(char *src, int pos, char *word) {
57	    int i = 0;
58	    while (word[i]) {
59	        if (src[pos + i] != word[i]) return 0;
60	        i++;
61	    }
62	    return i;  // return length of match (0 = no match since word is non-empty)
63	}
64	
65	// Check if character is a lowercase letter (a-z)
66	int is_lower(int ch) {
67	    return ch >= 97 && ch <= 122;
68	}
69	
70	// Check if character is an uppercase letter (A-Z)
71	int is_upper(int ch) {
72	    return ch >= 65 && ch <= 90;
73	}
74	
75	// Check if character is a digit (0-9)
76	int is_digit(int ch) {
77	    return ch >= 48 && ch <= 57;
78	}
79	
80	// Check if character is alphanumeric or underscore
81	int is_alnum(int ch) {
82	    return is_lower(ch) || is_upper(ch) || is_digit(ch);
83	}
84	
85	// ---- Reserved word lookup ----
86	// Returns reserved word ID if the lowercase word starting at pos matches,
87	// or -1 if not a reserved word. Sets *end to position past the word.
88	int lookup_reserved(char *src, int pos, int *end) {
89	    int len;
90	
91	    len = str_match(src, pos, "rho");
92	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
93	
94	    len = str_match(src, pos, "iota");
95	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }
96	
97	    len = str_match(src, pos, "take");
98	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }
99	
100	    len = str_match(src, pos, "drop");
101	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }
102	
103	    len = str_match(src, pos, "rev");
104	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_REV; }
105	
106	    len = str_match(src, pos, "cat");
107	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_CAT; }
108	
109	    len = str_match(src, pos, "and");
110	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_AND; }
111	
112	    len = str_match(src, pos, "or");
113	    if (len == 2 && !is_alnum(src[pos + 2])) { *end = pos + 2; return RES_OR; }
114	
115	    len = str_match(src, pos, "not");
116	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_NOT; }
117	
118	    return -1;
119	}
120	
121	// ---- Tokenizer ----
122	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
123	// Returns number of tokens (also stored in tok_count).
124	// On error, returns -1 (unrecognized character).
125	int tokenize(char *line) {
126	    int i = 0;
127	    int t = 0;
128	
129	    while (line[i] && t < TOK_MAX - 1) {
130	        // Skip whitespace
131	        if (line[i] == 32) {
132	            i++;
133	            continue;
134	        }
135	
136	        // Number: digits, or underscore followed by digit (APL negative)
137	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
138	            tok_type[t] = TOK_NUM;
139	            tok_pos[t] = i;
140	            int end;
141	            tok_val[t] = parse_int(line, i, &end);
142	            i = end;
143	            t++;
144	            continue;
145	        }
146	
147	        // Lowercase letter: quad variables, reserved word, or unknown
148	        if (is_lower(line[i])) {
149	            // Check for quad variables first
150	            int len;
151	            len = str_match(line, i, "qled");
152	            if (len == 4 && !is_alnum(line[i + 4])) {
153	                tok_type[t] = TOK_QLED;
154	                tok_pos[t] = i;
155	                tok_val[t] = 0;
156	                t++;
157	                i = i + 4;
158	                continue;
159	            }
160	
161	            len = str_match(line, i, "qsw");
162	            if (len == 3 && !is_alnum(line[i + 3])) {
163	                tok_type[t] = TOK_QSW;
164	                tok_pos[t] = i;
165	                tok_val[t] = 0;
166	                t++;
167	                i = i + 3;
168	                continue;
169	            }
170	
171	            len = str_match(line, i, "qsvo");
172	            if (len == 4 && !is_alnum(line[i + 4])) {
173	                tok_type[t] = TOK_QSVO;
174	                tok_pos[t] = i;
175	                tok_val[t] = 0;
176	                t++;
177	                i = i + 4;
178	                continue;
179	            }
180	
181	            len = str_match(line, i, "goto");
182	            if (len == 4 && !is_alnum(line[i + 4])) {
183	                tok_type[t] = TOK_GOTO;
184	                tok_pos[t] = i;
185	                tok_val[t] = 0;
186	                t++;
187	                i = i + 4;
188	                continue;
189	            }
190	
191	            int end;
192	            int res = lookup_reserved(line, i, &end);
193	            if (res >= 0) {
194	                tok_type[t] = TOK_RES;
195	                tok_val[t] = res;
196	                tok_pos[t] = i;
197	                i = end;
198	                t++;
199	                continue;
200	            }
201	            // Unknown lowercase word -- error
202	            return -1;
203	        }
204	
205	        // String literal: 'ABC' (single-quoted, for qsvo left argument)
206	        if (line[i] == 39) {
207	            // 39 = single quote
208	            i++;
209	            tok_type[t] = TOK_STRING;
210	            tok_pos[t] = i;  // position of first char
211	            tok_val[t] = i;  // store start of string content
212	            while (line[i] && line[i] != 39) i++;
213	            if (line[i] != 39) return -1;  // unterminated string
214	            i++;  // skip closing quote
215	            t++;
216	            continue;
217	        }
218	
219	        // Uppercase letter: user identifier
220	        if (is_upper(line[i])) {
221	            tok_type[t] = TOK_IDENT;
222	            tok_pos[t] = i;
223	            tok_val[t] = i;  // store start position for name extraction
224	            i++;
225	            while (is_alnum(line[i])) i++;
226	            t++;
227	            continue;
228	        }
229	
230	        // Operators and punctuation
231	        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
232	        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
233	        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
234	        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
235	        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
236	        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
237	
238	        // Quad: [] (IBM 5100 ASCII convention for ⎕) or bracket indexing [expr]
239	        if (line[i] == 91) {
240	            if (line[i + 1] == 93) {
241	                // [] = quad
242	                tok_type[t] = TOK_QUAD;
243	                tok_pos[t] = i;
244	                tok_val[t] = 0;
245	                t++;
246	                i = i + 2;
247	            } else {
248	                // [ = bracket index open
249	                tok_type[t] = TOK_LBRAK;
250	                tok_pos[t] = i;
251	                tok_val[t] = 0;
252	                t++;
253	                i++;
254	            }
255	            continue;
256	        }
257	        if (line[i] == 93) {
258	            tok_type[t] = TOK_RBRAK;
259	            tok_pos[t] = i;
260	            tok_val[t] = 0;
261	            t++;
262	            i++;
263	            continue;
264	        }
265	
266	        // Assignment: <-
267	        if (line[i] == 60 && line[i + 1] == 45) {
268	            tok_type[t] = TOK_ASSIGN;
269	            tok_pos[t] = i;
270	            tok_val[t] = 0;
271	            t++;
272	            i = i + 2;
273	            continue;
274	        }
275	
276	        // Comparison operators: = != >= <= > <
277	        // 61 '='  33 '!'  62 '>'  60 '<'
278	        if (line[i] == 61) { tok_type[t] = TOK_EQ; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
279	        if (line[i] == 33 && line[i + 1] == 61) { tok_type[t] = TOK_NE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
280	        if (line[i] == 62 && line[i + 1] == 61) { tok_type[t] = TOK_GE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
281	        if (line[i] == 60 && line[i + 1] == 61) { tok_type[t] = TOK_LE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
282	        if (line[i] == 62) { tok_type[t] = TOK_GT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
283	        if (line[i] == 60) { tok_type[t] = TOK_LT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
284	
285	        // Unrecognized character
286	        return -1;
287	    }
288	
289	    // Append EOL sentinel
290	    tok_type[t] = TOK_EOL;
291	    tok_pos[t] = i;
292	    tok_val[t] = 0;
293	    t++;
294	    tok_count = t;
295	    return t;
296	}
297	
298	// ---- Debug: print token list ----
299	// Useful for testing the tokenizer in isolation.
300	void tok_dump(char *line) {
301	    int i = 0;
302	    while (i < tok_count) {
303	        int ty = tok_type[i];
304	        if (ty == TOK_EOL) {
305	            io_print("EOL");
306	        } else if (ty == TOK_NUM) {
307	            io_print("NUM:");
308	            print_int(tok_val[i]);
309	        } else if (ty == TOK_IDENT) {
310	            io_print("ID:");
311	            int p = tok_val[i];
312	            while (is_alnum(line[p])) {
313	                putchar(line[p]);
314	                p++;
315	            }
316	        } else if (ty == TOK_RES) {
317	            io_print("RES:");
318	            int r = tok_val[i];
319	            if (r == RES_RHO)  io_print("rho");
320	            if (r == RES_IOTA) io_print("iota");
321	            if (r == RES_TAKE) io_print("take");
322	            if (r == RES_DROP) io_print("drop");
323	            if (r == RES_REV)  io_print("rev");
324	            if (r == RES_CAT)  io_print("cat");
325	        } else if (ty == TOK_PLUS)   { putchar(43); }
326	          else if (ty == TOK_MINUS)  { putchar(45); }
327	          else if (ty == TOK_STAR)   { putchar(42); }
328	          else if (ty == TOK_SLASH)  { putchar(47); }
329	          else if (ty == TOK_LPAREN) { putchar(40); }
330	          else if (ty == TOK_RPAREN) { putchar(41); }
331	          else if (ty == TOK_ASSIGN) { io_print("<-"); }
332	
333	        if (tok_type[i + 1] != TOK_EOL || ty == TOK_EOL) {
334	            // nothing
335	        }
336	        if (i + 1 < tok_count) putchar(32);
337	        i++;
338	    }
339	    putchar(10);
340	}
