1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
24	#define NODE_SVO_READ  14   // shared var indexed read (val = sym index, right = index expr)
25	#define NODE_SVO_WRITE 15  // shared var indexed write (val = sym index, left = index, right = value)
26	#define NODE_GOTO  16   // unconditional branch (right = target expr)
27	#define NODE_CGOTO 17   // conditional branch (left = cond, right = target)
28	#define NODE_FNCALL 18  // user function call (val = fn index, left = left arg/-1, right = right arg)
29	
30	#define AST_MAX 64
31	
32	// AST storage (parallel arrays)
33	int node_type[AST_MAX];
34	int node_val[AST_MAX];
35	int node_left[AST_MAX];
36	int node_right[AST_MAX];
37	int node_count;
38	
39	// Parser state
40	int parse_pos;
41	int parse_err;
42	char *parse_line;   // source line for identifier lookup
43	
44	// Allocate a new AST node
45	int ast_new() {
46	    if (node_count >= AST_MAX) {
47	        parse_err = 1;
48	        return 0;
49	    }
50	    int n = node_count;
51	    node_count++;
52	    node_left[n] = -1;
53	    node_right[n] = -1;
54	    return n;
55	}
56	
57	int ast_num(int val) {
58	    int n = ast_new();
59	    node_type[n] = NODE_NUM;
60	    node_val[n] = val;
61	    return n;
62	}
63	
64	int ast_binop(int op, int left, int right) {
65	    int n = ast_new();
66	    node_type[n] = NODE_BINOP;
67	    node_val[n] = op;
68	    node_left[n] = left;
69	    node_right[n] = right;
70	    return n;
71	}
72	
73	int ast_neg(int operand) {
74	    int n = ast_new();
75	    node_type[n] = NODE_NEG;
76	    node_right[n] = operand;
77	    return n;
78	}
79	
80	int ast_ident(int sym_idx) {
81	    int n = ast_new();
82	    node_type[n] = NODE_IDENT;
83	    node_val[n] = sym_idx;
84	    return n;
85	}
86	
87	int ast_assign(int sym_idx, int expr) {
88	    int n = ast_new();
89	    node_type[n] = NODE_ASSIGN;
90	    node_val[n] = sym_idx;
91	    node_right[n] = expr;
92	    return n;
93	}
94	
95	int ast_vec(int heap_idx) {
96	    int n = ast_new();
97	    node_type[n] = NODE_VEC;
98	    node_val[n] = heap_idx;
99	    return n;
100	}
101	
102	int ast_monad(int res_id, int operand) {
103	    int n = ast_new();
104	    node_type[n] = NODE_MONAD;
105	    node_val[n] = res_id;
106	    node_right[n] = operand;
107	    return n;
108	}
109	
110	int ast_dyad(int res_id, int left, int right) {
111	    int n = ast_new();
112	    node_type[n] = NODE_DYAD;
113	    node_val[n] = res_id;
114	    node_left[n] = left;
115	    node_right[n] = right;
116	    return n;
117	}
118	
119	int ast_reduce(int op, int operand) {
120	    int n = ast_new();
121	    node_type[n] = NODE_REDUCE;
122	    node_val[n] = op;
123	    node_right[n] = operand;
124	    return n;
125	}
126	
127	// Check if a reserved word can be used dyadically
128	int is_dyadic_res(int res_id) {
129	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR;
130	}
131	
132	// Temporary buffer for collecting strand elements
133	int strand_buf[64];
134	
135	int is_binop(int ty) {
136	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH ||
137	           ty == TOK_EQ || ty == TOK_NE || ty == TOK_LT || ty == TOK_GT ||
138	           ty == TOK_LE || ty == TOK_GE;
139	}
140	
141	// Check if token at pos could start an expression (for function call detection)
142	int can_start_expr(int pos) {
143	    int ty = tok_type[pos];
144	    if (ty == TOK_NUM || ty == TOK_LPAREN || ty == TOK_IDENT ||
145	        ty == TOK_MINUS || ty == TOK_RES || ty == TOK_QLED || ty == TOK_QSW) return 1;
146	    if (is_binop(ty) && tok_type[pos + 1] == TOK_SLASH) return 1;  // reduce
147	    return 0;
148	}
149	
150	// Combined parse function avoids mutual recursion.
151	// mode 0 = expression, mode 1 = value only
152	int parse_node(int mode);
153	
154	int parse_node(int mode) {
155	    if (parse_err) return 0;
156	
157	    int left;
158	    int ty = tok_type[parse_pos];
159	
160	    // -- Parse a value --
161	
162	    if (ty == TOK_NUM) {
163	        left = ast_num(tok_val[parse_pos]);
164	        parse_pos++;
165	
166	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
167	        if (tok_type[parse_pos] == TOK_NUM) {
168	            strand_buf[0] = node_val[left];
169	            int count = 1;
170	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
171	                strand_buf[count] = tok_val[parse_pos];
172	                parse_pos++;
173	                count++;
174	            }
175	            int aidx = arr_vector(count);
176	            if (aidx < 0) { parse_err = 1; return 0; }
177	            int si = 0;
178	            while (si < count) {
179	                arr_set(aidx, si, strand_buf[si]);
180	                si++;
181	            }
182	            left = ast_vec(aidx);
183	        }
184	    } else if (ty == TOK_LPAREN) {
185	        parse_pos++;
186	        left = parse_node(0);
187	        if (parse_err) return 0;
188	        if (tok_type[parse_pos] != TOK_RPAREN) {
189	            parse_err = 1;
190	            return 0;
191	        }
192	        parse_pos++;
193	    } else if (ty == TOK_QLED) {
194	        int n = ast_new();
195	        node_type[n] = NODE_QLED;
196	        left = n;
197	        parse_pos++;
198	    } else if (ty == TOK_QSW) {
199	        int n = ast_new();
200	        node_type[n] = NODE_QSW;
201	        left = n;
202	        parse_pos++;
203	    } else if (ty == TOK_STRING) {
204	        // String literal becomes an identifier (for 'NAME' qsvo AP)
205	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
206	        if (sym_idx < 0) { parse_err = 1; return 0; }
207	        left = ast_ident(sym_idx);
208	        parse_pos++;
209	    } else if (ty == TOK_IDENT) {
210	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
211	        if (sym_idx < 0) { parse_err = 1; return 0; }
212	        parse_pos++;
213	        // Check for monadic function call
214	        int fi = fn_lookup(sym_idx);
215	        if (fi >= 0 && fn_left_sym[fi] < 0 && can_start_expr(parse_pos)) {
216	            // Monadic user function call: FN expr
217	            int arg = parse_node(0);
218	            if (parse_err) return 0;
219	            int nd = ast_new();
220	            node_type[nd] = NODE_FNCALL;
221	            node_val[nd] = fi;
222	            node_right[nd] = arg;
223	            left = nd;
224	        } else if (tok_type[parse_pos] == TOK_LBRAK) {
225	            // IDENT[expr] -- shared variable indexed read
226	            parse_pos++;
227	            int idx_expr = parse_node(0);
228	            if (parse_err) return 0;
229	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
230	            parse_pos++;
231	            int nd = ast_new();
232	            node_type[nd] = NODE_SVO_READ;
233	            node_val[nd] = sym_idx;
234	            node_right[nd] = idx_expr;
235	            left = nd;
236	        } else {
237	            left = ast_ident(sym_idx);
238	        }
239	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
240	        // Reduce operator: +/ -/ */ (op followed by slash)
241	        int op = ty;
242	        parse_pos = parse_pos + 2;
243	        int operand = parse_node(0);
244	        if (parse_err) return 0;
245	        left = ast_reduce(op, operand);
246	    } else if (ty == TOK_RES) {
247	        // Monadic primitive function (e.g. iota expr)
248	        int res_id = tok_val[parse_pos];
249	        parse_pos++;
250	        int operand = parse_node(0);
251	        if (parse_err) return 0;
252	        left = ast_monad(res_id, operand);
253	    } else if (ty == TOK_MINUS) {
254	        // Monadic negate: applies to entire right expression (APL rule)
255	        parse_pos++;
256	        int operand = parse_node(0);
257	        if (parse_err) return 0;
258	        left = ast_neg(operand);
259	    } else {
260	        parse_err = 1;
261	        return 0;
262	    }
263	
264	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
265	
266	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
267	        int op = tok_type[parse_pos];
268	        parse_pos++;
269	        int right = parse_node(0);
270	        if (parse_err) return 0;
271	        return ast_binop(op, left, right);
272	    }
273	
274	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
275	        int res_id = tok_val[parse_pos];
276	        parse_pos++;
277	        int right = parse_node(0);
278	        if (parse_err) return 0;
279	        return ast_dyad(res_id, left, right);
280	    }
281	
282	    // Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
283	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
284	        int sym_idx = node_val[left];
285	        parse_pos++;
286	        int right = parse_node(0);
287	        if (parse_err) return 0;
288	        int n = ast_new();
289	        node_type[n] = NODE_QSVO;
290	        node_val[n] = sym_idx;
291	        node_right[n] = right;
292	        return n;
293	    }
294	
295	    // Dyadic user function call: expr FN expr
296	    if (mode == 0 && tok_type[parse_pos] == TOK_IDENT) {
297	        int dsym = sym_lookup(parse_line, tok_val[parse_pos]);
298	        if (dsym >= 0) {
299	            int dfi = fn_lookup(dsym);
300	            if (dfi >= 0 && fn_left_sym[dfi] >= 0) {
301	                parse_pos++;
302	                int right = parse_node(0);
303	                if (parse_err) return 0;
304	                int nd = ast_new();
305	                node_type[nd] = NODE_FNCALL;
306	                node_val[nd] = dfi;
307	                node_left[nd] = left;
308	                node_right[nd] = right;
309	                return nd;
310	            }
311	        }
312	    }
313	
314	    return left;
315	}
316	
317	// Parse the token stream. Returns root node index, or -1 on error.
318	// line is needed for identifier name resolution into the symbol table.
319	int parse(char *line) {
320	    node_count = 0;
321	    parse_pos = 0;
322	    parse_err = 0;
323	    parse_line = line;
324	
325	    // Check for qled assignment: qled <- expr
326	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
327	        parse_pos = 2;
328	        int expr = parse_node(0);
329	        if (parse_err) return -1;
330	        if (tok_type[parse_pos] != TOK_EOL) return -1;
331	        int n = ast_new();
332	        node_type[n] = NODE_QLED_ASSIGN;
333	        node_right[n] = expr;
334	        return n;
335	    }
336	
337	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
338	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
339	        return -1;
340	    }
341	
342	    // Check for quad output: [] <- expr (IBM 5100 convention)
343	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
344	        parse_pos = 2;
345	        int expr = parse_node(0);
346	        if (parse_err) return -1;
347	        if (tok_type[parse_pos] != TOK_EOL) return -1;
348	        int n = ast_new();
349	        node_type[n] = NODE_QOUT;
350	        node_right[n] = expr;
351	        return n;
352	    }
353	
354	    // Check for shared variable indexed write: IDENT[expr] <- expr
355	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
356	        int sym_idx = sym_lookup(line, tok_val[0]);
357	        if (sym_idx < 0) { return -1; }
358	        parse_pos = 2;
359	        int idx_expr = parse_node(0);
360	        if (parse_err) return -1;
361	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
362	        parse_pos++;
363	        if (tok_type[parse_pos] == TOK_ASSIGN) {
364	            // IDENT[expr] <- expr (indexed write)
365	            parse_pos++;
366	            int val_expr = parse_node(0);
367	            if (parse_err) return -1;
368	            if (tok_type[parse_pos] != TOK_EOL) return -1;
369	            int n = ast_new();
370	            node_type[n] = NODE_SVO_WRITE;
371	            node_val[n] = sym_idx;
372	            node_left[n] = idx_expr;
373	            node_right[n] = val_expr;
374	            return n;
375	        }
376	        if (tok_type[parse_pos] != TOK_EOL) {
377	            // IDENT[expr] followed by more (could be in expression context)
378	            // For now, only standalone read supported at top level
379	            // Fall through to expression parsing below
380	            parse_pos = 0;
381	            node_count = 0;
382	            parse_err = 0;
383	        } else {
384	            // IDENT[expr] standalone read
385	            int n = ast_new();
386	            node_type[n] = NODE_SVO_READ;
387	            node_val[n] = sym_idx;
388	            node_right[n] = idx_expr;
389	            return n;
390	        }
391	    }
392	
393	    // Check for goto: goto expr  or  goto (expr)/LABEL
394	    if (tok_type[0] == TOK_GOTO) {
395	        parse_pos = 1;
396	        if (tok_type[1] == TOK_LPAREN) {
397	            // Conditional: goto (expr)/TARGET
398	            parse_pos = 2;
399	            int cond = parse_node(0);
400	            if (parse_err) return -1;
401	            if (tok_type[parse_pos] != TOK_RPAREN) return -1;
402	            parse_pos++;
403	            if (tok_type[parse_pos] != TOK_SLASH) return -1;
404	            parse_pos++;
405	            int target = parse_node(0);
406	            if (parse_err) return -1;
407	            if (tok_type[parse_pos] != TOK_EOL) return -1;
408	            int n = ast_new();
409	            node_type[n] = NODE_CGOTO;
410	            node_left[n] = cond;
411	            node_right[n] = target;
412	            return n;
413	        }
414	        // Unconditional: goto expr
415	        int target = parse_node(0);
416	        if (parse_err) return -1;
417	        if (tok_type[parse_pos] != TOK_EOL) return -1;
418	        int n = ast_new();
419	        node_type[n] = NODE_GOTO;
420	        node_right[n] = target;
421	        return n;
422	    }
423	
424	    // Check for assignment: IDENT <- expr
425	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
426	        int sym_idx = sym_lookup(line, tok_val[0]);
427	        if (sym_idx < 0) { return -1; }
428	        parse_pos = 2;
429	        int expr = parse_node(0);
430	        if (parse_err) return -1;
431	        if (tok_type[parse_pos] != TOK_EOL) return -1;
432	        return ast_assign(sym_idx, expr);
433	    }
434	
435	    int root = parse_node(0);
436	
437	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
438	        parse_err = 1;
439	    }
440	
441	    if (parse_err) return -1;
442	    return root;
443	}
444	
445	// Debug: dump AST with full parenthesization
446	void ast_dump(int n) {
447	    if (n < 0 || n >= node_count) return;
448	
449	    int ty = node_type[n];
450	    if (ty == NODE_NUM) {
451	        print_int(node_val[n]);
452	    } else if (ty == NODE_BINOP) {
453	        putchar(40);
454	        ast_dump(node_left[n]);
455	        putchar(32);
456	        if (node_val[n] == TOK_PLUS)  putchar(43);
457	        if (node_val[n] == TOK_MINUS) putchar(45);
458	        if (node_val[n] == TOK_STAR)  putchar(42);
459	        if (node_val[n] == TOK_SLASH) putchar(47);
460	        putchar(32);
461	        ast_dump(node_right[n]);
462	        putchar(41);
463	    } else if (ty == NODE_NEG) {
464	        putchar(40);
465	        putchar(45);
466	        ast_dump(node_right[n]);
467	        putchar(41);
468	    }
469	}
